-- "Парящая долина" — без координат, без содержания
UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Парящая долина — народное название гидротермальных долин Камчатки, где над поверхностью постоянно висит пар от горячих источников. Термин применяется к нескольким местам полуострова: Налычевская долина, Долина гейзеров, Мутновское нагорье. Зимой эффект «парящей» земли особенно выразителен.'
WHERE id = '3b7737cd-6ee2-42c3-8117-725bbf1c9f31';

-- "ТРОПА МЕДВЕДЯ (ДОЛИНА СМЕРТИ)" — это реальный объект!
UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Тропа медведя — маршрут в Долину смерти Камчатки, расположенную в верховьях реки Гейзерная рядом с Долиной гейзеров. Долина смерти — геологическая аномалия: скопление токсичных вулканических газов (CO₂, H₂S) в низинах убивает мелких животных и птиц. Медведи приходят сюда за лёгкой добычей — отсюда название «Тропа медведя». Посещение только с опытным гидом Кроноцкого заповедника.'
WHERE id = 'e552c8a2-52bd-4f7d-ad37-33b1a28460ab';

-- "Фумарола вулкана Дзендзур"
UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Фумарола вулкана Дзендзур — паровой выход на склоне вулкана Дзендзур (1178 м) в Восточном хребте Камчатки. Температура выходящего газа +80–120°С. Дзендзур — потенциально активный вулкан с постоянной фумарольной деятельностью. Посещается в рамках маршрутов по Налычевскому природному парку.'
WHERE id = '05112df7-54f9-4280-bcd2-1bfe4929dfc0';

-- "Чистинские (Аагские) нарзаны" — это не гейзер, а холодные нарзаны
UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Чистинские (Аагские) нарзаны — холодные углекислые железистые источники в Налычевском природном парке. Температура +8–12°С, CO₂ до 2 г/л, Fe²⁺ до 40 мг/л — природный нарзан с рыжим цветом от окисленного железа. Часть уникального термального комплекса Налычево (ЮНЕСКО). Используются для питьевого лечения: ЖКТ, ССС, анемия.'
WHERE id = '5fe02f54-d018-4125-a0ec-e5fc458ad493';
